// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('item title', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('item title', async function() {
    await driver.get("http://localhost:4200/home");
    await driver.manage().window().setRect({ width: 1900, height: 1020 });
    await driver.findElement(By.css(".ant-row:nth-child(3) .ant-typography")).click();
    await driver.findElement(By.xpath("//span[contains(.,\'公開専門スキル一覧\')]")).click();
    await driver.findElement(By.css(".main_button > span")).click();
    await driver.findElement(By.css(".ant-table-cell-row-hover:nth-child(1)")).click();
    assert(await driver.findElement(By.xpath("//h3[contains(.,\'専門スキル詳細\')]")).getText() == "専門スキル詳細");
    await driver.findElement(By.css(".ant-form-item:nth-child(1) .ant-form-item-no-colon")).click();
    assert(await driver.findElement(By.xpath("//label[contains(.,\'部署\')]")).getText() == "部署");
    assert(await driver.findElement(By.xpath("//label[contains(.,\'バージョン\')]")).getText() == "バージョン");
    assert(await driver.findElement(By.xpath("//label[contains(.,\'状態\')]")).getText() == "状態");
    assert(await driver.findElement(By.xpath("//label[contains(.,\'公開ステータス\')]")).getText() == "公開ステータス");
    assert(await driver.findElement(By.xpath("//label[contains(.,\'最終更新者\')]")).getText() == "最終更新者");
    assert(await driver.findElement(By.xpath("//label[contains(.,\'最終更新日\')]")).getText() == "最終更新日");
    assert(await driver.findElement(By.xpath("//label[contains(.,\'公開日\')]")).getText() == "公開日");
    assert(await driver.findElement(By.xpath("//h4[contains(.,\'専門スキル評価項目一覧\')]")).getText() == "専門スキル評価項目一覧");
    assert(await driver.findElement(By.xpath("//th[contains(.,\'職種\')]")).getText() == "職種");
    assert(await driver.findElement(By.xpath("//th[contains(.,\'大・中分類\')]")).getText() == "大・中分類");
    assert(await driver.findElement(By.xpath("//th[contains(.,\'小分類\')]")).getText() == "小分類");
    assert(await driver.findElement(By.xpath("//th[contains(.,\'評価内容\')]")).getText() == "評価内容");
    assert(await driver.findElement(By.xpath("//th[contains(.,\'難易度\')]")).getText() == "難易度");
    assert(await driver.findElement(By.xpath("//th[contains(.,\'備考\')]")).getText() == "備考");
  });
});
